import UIKit

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?

    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        if let host = url.host, host == "myapp.com", let components = NSURLComponents(url: url, resolvingAgainstBaseURL: true), let queryItems = components.queryItems {
